    ["Show this HUD element while your cursor is hovering over its anchor area."] = "Afficher cet élément HUD lorsque votre curseur survole sa zone d’ancrage.",
    ["Show this currency on the bag window's currency bar. Use the arrows to reorder."] = "Afficher cette monnaie sur la barre de monnaies de la fenêtre de sac. Utilisez les flèches pour réorganiser.",
    ["Show tick marks on the bar at the stage boundaries configured by Tick Style."] = "Afficher des marques sur la barre aux limites de phase configurées par Style de marqueur.",
    ["Show your current flight speed next to the vigor bar."] = "Afficher votre vitesse de vol actuelle à côté de la barre de Vigueur.",
    ["Show/hide the bag-slot strip"] = "Afficher/masquer la rangée d'emplacements de sacs",
    ["Shown in the bottom-left corner when the primary widget doesn't apply."] = "Affiché en bas à gauche quand le widget principal ne s’applique pas.",
    ["Shown in the bottom-right corner when the primary widget doesn't apply."] = "Affiché en bas à droite quand le widget principal ne s’applique pas.",
    ["Shown in the top-left corner when the primary widget doesn't apply to the item."] = "Affiché en haut à gauche quand le widget principal ne s’applique pas à l’objet.",
    ["Shown in the top-right corner when the primary widget doesn't apply."] = "Affiché en haut à droite quand le widget principal ne s’applique pas.",
    ["Shows a brief text flash when entering or leaving combat."] = "Affiche un bref flash de texte à l’entrée ou à la sortie du combat.",
    ["Shows an icon indicating if the unit is Elite, Rare, Rare Elite, or a Boss."] = "Affiche une icône indiquant si l’unité est élite, rare, rare-élite ou un boss.",
    ["Shows available hunts when visiting a hunt table NPC."] = "Affiche les chasses disponibles lors de la visite d’un PNJ de table de chasse.",
    ["Shows boss debuffs and other private auras on this unit frame. The client renders the icon, cooldown spiral, and stack/duration text."] = "Affiche les debuffs de boss et autres auras privées sur ce cadre d’unité. Le client rend l’icône, la spirale de recharge et le texte de pile/durée.",
    ["Shows crown icon for party/raid leader, flag icon for raid assistants."] = "Affiche l’icône de couronne pour le chef de groupe/raid, l’icône de drapeau pour les assistants de raid.",
    ["Shows during combat (disabled by default)."] = "Affiché en combat (désactivé par défaut).",
    ["Shows raid target markers (skull, cross, diamond, etc.) on the unit frame."] = "Affiche les marqueurs de cible de raid (crâne, croix, losange, etc.) sur le cadre d’unité.",
    ["Shows remaining battle-resurrection charges for the group."] = "Affiche les charges restantes de résurrection de combat pour le groupe.",
    ["Shows when in a rested area (disabled by default)."] = "Affiché dans une zone de repos (désactivé par défaut).",
    ["Shows which raid-wide utility buffs are absent from the group."] = "Affiche quels buffs utilitaires à l’échelle du raid sont absents du groupe.",
    ["Silence the voice audio that plays with talking head events, without hiding the frame itself."] = "Coupe l’audio vocal joué avec les événements de talking head, sans masquer le cadre lui-même.",
    ["Silvermoon Health Potion"] = "Potion de soin de Lune-d'Argent",
    ["Sixth action bar."] = "Sixième barre d’action.",
    ["Size"] = "Taille",
    ["Size & Text"] = "Taille et texte",
    ["Size Override"] = "Remplacement de taille",
    ["Size multiplier for Autocast Shine."] = "Multiplicateur de taille pour la brillance d’Autocast.",
    ["Size multiplier for the Autocast Shine glow."] = "Multiplicateur de taille pour la lueur d’Autocast Shine.",
    ["Size of the Second Wind pips (Pips mode only)."] = "Taille des pips de Second souffle (mode Pips uniquement).",
    ["Size of the particles in the AutoCast glow style."] = "Taille des particules pour le style d'éclat AutoCast.",
    ["Skin Alerts"] = "Alertes de skin",
    ["Skin Blizzard Frames"] = "Habiller les cadres Blizzard",
    ["Skin Game Menu (Req. Reload)"] = "Habiller le menu du jeu (rechargement requis)",
    ["Skin Loot Window (Req. Reload)"] = "Habiller la fenêtre de butin (rechargement requis)",
    ["Skin Objective Tracker"] = "Habiller le suivi des objectifs",
    ["Skin Ready Check Frame"] = "Habiller le cadre du ready check",
    ["Skin Roll Frames (Req. Reload)"] = "Habiller les cadres de jet (rechargement requis)",
    ["Skin StaticPopup confirmation dialogs. Requires a reload."] = "Habiller les boîtes de dialogue de confirmation StaticPopup. Nécessite un rechargement.",
    ["Skin Tooltips"] = "Habiller les info-bulles",
    ["Skin accent"] = "Accent du skin",
    ["Skin right-click context menus and dropdown menu panels. Requires a reload."] = "Habiller les menus contextuels de clic droit et les panneaux de menus déroulants. Nécessite un rechargement.",
    ["Skin the Achievements window. Bespoke achievement-themed artwork is stripped — categories list parchment and watermark dragon are hidden. Requires a reload."] = "Habille la fenêtre des succès. Les illustrations thématiques de succès spécifiques sont supprimées - la liste des catégories, le parchemin et le dragon filigrane sont masqués. Nécessite un rechargement.",
    ["Skin the Adventure Guide / Encounter Journal window. Requires a reload."] = "Habille la fenêtre Guide d’aventure / Journal des rencontres. Nécessite un rechargement.",
    ["Skin the Auction House window and its tabs. Requires a reload."] = "Habille la fenêtre de l’Hôtel des ventes et ses onglets. Nécessite un rechargement.",
    ["Skin the Crafting Orders interface used by professions. Requires a reload."] = "Habille l’interface de commandes d’artisanat utilisée par les professions. Nécessite un rechargement.",
    ["Skin the Friends / Ignore / Who window. Requires a reload."] = "Habille la fenêtre Amis / Ignorer / Qui. Nécessite un rechargement.",
    ["Skin the Great Vault window. Bespoke evergreen artwork is stripped. Requires a reload."] = "Habille la fenêtre du Grand coffre. Les illustrations persistantes spécifiques sont supprimées. Nécessite un rechargement.",
    ["Skin the Group Finder, PvP, and Mythic+ instance windows. Requires a reload."] = "Habille l’outil de recherche de groupe, JcJ et les fenêtres d’instance Mythic+. Nécessite un rechargement.",
    ["Skin the Guild Bank window. Requires a reload."] = "Habille la fenêtre de Banque de guilde. Nécessite un rechargement.",
    ["Skin the Guilds and Communities window. Requires a reload."] = "Habille la fenêtre Guilde et communautés. Nécessite un rechargement.",
    ["Skin the Inspect window that opens when you /inspect another player. Requires a reload."] = "Habille la fenêtre d’inspection qui s’ouvre quand vous /inspectez un autre joueur. Nécessite un rechargement.",
    ["Skin the Mounts / Pets / Toys / Wardrobe / Heirlooms window. Requires a reload."] = "Habille la fenêtre Montures / Familiers / Jouets / Garderobe / Héritages. Nécessite un rechargement.",
    ["Skin the Mythic+ Keystone insertion and selection window. Requires a reload."] = "Habille la fenêtre d’insertion et de sélection de clef Mythic+. Nécessite un rechargement.",
    ["Skin the World Map's PortraitFrame border (the map canvas itself is unchanged). Requires a reload."] = "Habille la bordure du PortraitFrame de la carte du monde (la toile de la carte elle-même ne change pas). Nécessite un rechargement.",
    ["Skin the achievement, loot, and level-up alert popups. Requires a reload."] = "Habille les popups de succès, butin et montée de niveau. Nécessite un rechargement.",
    ["Skin the alternate power bar some encounters use (e.g., boss add health bars). Requires a reload."] = "Habille la barre de puissance alternative utilisée par certains combats (ex. barres de vie d’ajouts de boss). Nécessite un rechargement.",
    ["Skin the combined Spellbook and Talents window (PlayerSpellsFrame). Requires a reload."] = "Habille la fenêtre combinée Grimoire et Talents (PlayerSpellsFrame). Nécessite un rechargement.",
    ["Skin the experience, reputation, and honor bars above the action bar. Requires a reload."] = "Habille les barres d’expérience, réputation et honneur au-dessus de la barre d’action. Nécessite un rechargement.",
    ["Skin the group loot history popup that summarizes recent drops. Requires a reload."] = "Habille la fenêtre d’historique de butin de groupe qui résume les derniers drops. Nécessite un rechargement.",
    ["Skin the in-game mail window. Requires a reload."] = "Habille la fenêtre de courrier en jeu. Nécessite un rechargement.",
    ["Skin the player Bank window. Requires a reload."] = "Habille la fenêtre Banque du joueur. Nécessite un rechargement.",
