    ["This cannot be undone."] = "Ceci ne peut pas être annulé.",
    ["This cannot be undone. Other characters' saved files are only loaded by WoW when that character logs in, so they will be wiped at their next login."] = "Ceci ne peut pas être annulé. Les fichiers sauvegardés des autres personnages ne sont chargés par WoW que lorsque ce personnage se connecte, ils seront donc effacés à leur prochaine connexion.",
    ["This cannot be undone. The cache rebuilds on the next guild bank visit."] = "Ceci ne peut pas être annulé. Le cache se reconstruit à la prochaine visite de la banque de guilde.",
    ["This cannot be undone. The cache rebuilds the next time that character logs in."] = "Ceci ne peut pas être annulé. Le cache se reconstruit la prochaine fois que ce personnage se connecte.",
    ["This change requires a reload to take effect."] = "Ce changement nécessite un rechargement pour être appliqué.",
